"use client"
export const DatePickerWithPresetsSidebar = () => {
  return (
    <DatePicker.Root inline fixedWeeks width="fit-content" borderWidth="1px">
      <Flex flexDirection={{ base: "column", sm: "row" }}>
        <Stack
          gap="0"
          minW={{ base: "full", sm: "2xs" }}
          borderBottomWidth={{ base: "1px", sm: "0" }}
          borderEndWidth={{ base: "0", sm: "1px" }}
          py="2"
        >
          {presets.map((preset) => (
            <DatePicker.Context key={preset.label}>
              {(ctx) => (
                <DatePicker.PresetTrigger
                  value={[preset.value]}
                  height="10"
                  display="flex"
                  justifyContent="space-between"
                  alignItems="center"
                  px="4"
                  textStyle="sm"
                  gap="1"
                  data-selected={
                    ctx.value.length > 0 &&
                    preset.value.compare(ctx.value[0]) === 0
                      ? ""
                      : undefined
                  }
                  _selected={{
                    layerStyle: "fill.subtle",
                  }}
                >
                  <Span>{preset.label}</Span>
                  <Span color="fg.muted" textStyle="sm">
                    {formatShortDate(preset.value, preset.value.toDate(tz))}
                  </Span>
                </DatePicker.PresetTrigger>
              )}
            </DatePicker.Context>
          ))}
        </Stack>

        <DatePicker.View view="day" p="3">
          <HStack justify="space-between" gap="0">
            <DatePicker.RangeText ps="4" fontWeight="medium" />
            <Spacer />
            <DatePicker.PrevTrigger />
            <DatePicker.NextTrigger />
          </HStack>
          <DatePicker.DayTable />
        </DatePicker.View>
      </Flex>
    </DatePicker.Root>
  )
}

const tz = getLocalTimeZone()
const now = today(tz)

const presets = [
  { label: "Today", value: now },
  { label: "Tomorrow", value: now.add({ days: 1 }) },
  { label: "Next week", value: now.add({ weeks: 1 }) },
  { label: "2 weeks", value: now.add({ weeks: 2 }) },
  { label: "4 weeks", value: now.add({ weeks: 4 }) },
]

const weekdayFormatter = new DateFormatter("en-US", { weekday: "short" })
const shortDateFormatter = new DateFormatter("en-US", {
  day: "numeric",
  month: "short",
})

const tomorrow = now.add({ days: 1 })
const formatShortDate = (value: DateValue, display: Date) => {
  if (isToday(value, tz)) return weekdayFormatter.format(display)
  if (isSameDay(value, tomorrow)) return weekdayFormatter.format(display)
  return shortDateFormatter.format(display)
}

"use client"
const tz = getLocalTimeZone()

export const DatePickerWithTimeGrid = () => {
  const [selectedDate, setSelectedDate] = useState<DateValue[]>([])
  const [selectedTime, setSelectedTime] = useState<Time | null>(null)

  const date = selectedDate[0]
  const slots = date ? generateTimeSlots(date) : []
  const nativeDate = date?.toDate(tz)

  const handleDateChange = (details: { value: DateValue[] }) => {
    setSelectedDate(details.value)
    setSelectedTime(null)
  }

  const handleTimeClick = (time: Time) => {
    setSelectedTime(
      selectedTime && selectedTime.compare(time) === 0 ? null : time,
    )
  }

  return (
    <Flex
      direction={{ base: "column", md: "row" }}
      borderWidth="1px"
      rounded="xl"
      overflow="hidden"
      width="fit-content"
    >
      {/* Calendar */}
      <Box
        borderEndWidth={{ md: "1px" }}
        borderBottomWidth={{ base: "1px", md: "0" }}
      >
        <Stack gap="0" px="5" py="5">
          <Text fontWeight="semibold" textStyle="lg">
            Select a Date
          </Text>
          <Text textStyle="sm" color="fg.muted">
            Pick a day for your meeting
          </Text>
        </Stack>

        <DatePicker.Root
          inline
          value={selectedDate}
          onValueChange={handleDateChange}
          isDateUnavailable={(date) => isWeekend(date, "en-US")}
          width="fit-content"
        >
          <DatePicker.Content unstyled px="3" pb="4">
            <DatePicker.View view="day">
              <HStack justify="space-between" gap="0">
                <DatePicker.PrevTrigger />
                <DatePicker.RangeText fontWeight="medium" textStyle="sm" />
                <DatePicker.NextTrigger />
              </HStack>
              <DatePicker.DayTable />
            </DatePicker.View>
          </DatePicker.Content>
        </DatePicker.Root>

        <HStack px="5" pb="4" color="fg.muted" textStyle="xs">
          <LuGlobe />
          <span>{tz}</span>
        </HStack>
      </Box>

      {/* Time slots */}
      <Stack minW="240px" flex="1">
        {date && nativeDate ? (
          <Stack gap="0" flex="1">
            <Stack gap="0" px="5" pt="5" pb="3">
              <Text fontWeight="semibold">
                {isToday(date, tz) ? "Today" : formatWeekday(nativeDate)}
              </Text>
              <Text textStyle="sm" color="fg.muted">
                {formatMonthDay(nativeDate)}
              </Text>
            </Stack>

            <TimeGrid
              slots={slots}
              selectedTime={selectedTime}
              onTimeClick={handleTimeClick}
            />
          </Stack>
        ) : (
          <Center height="full" px="8" py="10" color="fg.muted">
            <Stack align="center" gap="1" textAlign="center">
              <Text textStyle="sm" fontWeight="medium">
                Select a date
              </Text>
              <Text textStyle="xs">Available time slots will appear here</Text>
            </Stack>
          </Center>
        )}
      </Stack>
    </Flex>
  )
}

/* --- TimeGrid component --- */

interface TimeGridProps {
  slots: Time[]
  selectedTime: Time | null
  onTimeClick: (time: Time) => void
}

const TimeGrid = (props: TimeGridProps) => {
  const { slots, selectedTime, onTimeClick } = props

  return (
    <Stack gap="2" px="4" pb="4" flex="1" overflowY="auto" maxH="380px">
      {slots.map((time) => {
        const isSelected =
          selectedTime != null && selectedTime.compare(time) === 0
        const label = formatTime(time)

        return (
          <Button
            key={label}
            variant={isSelected ? "solid" : "outline"}
            size="sm"
            rounded="lg"
            fontWeight="semibold"
            onClick={() => onTimeClick(time)}
          >
            {label}
          </Button>
        )
      })}
    </Stack>
  )
}

/* --- Utilities --- */

const generateTimeSlots = (date: DateValue): Time[] => {
  const day = date.toDate(tz).getDay()
  const slots: Time[] = []
  const start = 9
  const end = day === 5 ? 14 : 17

  for (let hour = start; hour < end; hour++) {
    slots.push(new Time(hour, 0))
    if (hour < end - 1 || day !== 5) {
      slots.push(new Time(hour, 30))
    }
  }

  // simulate some unavailable slots
  const seed = date.day + date.month
  return slots.filter((_, i) => (i + seed) % 5 !== 0)
}

const formatTime = (time: Time) =>
  `${String(time.hour).padStart(2, "0")}:${String(time.minute).padStart(2, "0")}`

const formatWeekday = (date: Date) =>
  date.toLocaleDateString("en-US", { weekday: "long" })

const formatMonthDay = (date: Date) =>
  date.toLocaleDateString("en-US", { month: "long", day: "numeric" })

"use client"
const formatter = new DateFormatter("en-US", {
  month: "short",
  day: "numeric",
  year: "numeric",
  hour: "numeric",
  minute: "2-digit",
})

export const DatePickerWithTime = () => {
  const [value, setValue] = useState<CalendarDateTime[]>([
    new CalendarDateTime(2025, 1, 29, 14, 30),
  ])

  const timeValue = value[0]
    ? `${String(value[0].hour).padStart(2, "0")}:${String(value[0].minute).padStart(2, "0")}`
    : ""

  const onTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const [hours, minutes] = e.currentTarget.value.split(":").map(Number)
    setValue((prev) => {
      const current = prev[0] ?? new CalendarDateTime(2025, 1, 1, 0, 0)
      return [current.set({ hour: hours, minute: minutes })]
    })
  }

  const onDateChange = (details: { value: DateValue[] }) => {
    const newDate = details.value[0]
    if (!newDate) return setValue([])
    const prevTime = value[0] ?? { hour: 0, minute: 0 }
    setValue([
      new CalendarDateTime(
        newDate.year,
        newDate.month,
        newDate.day,
        prevTime.hour,
        prevTime.minute,
      ),
    ])
  }

  return (
    <DatePicker.Root
      value={value}
      onValueChange={onDateChange}
      closeOnSelect={false}
      maxWidth="20rem"
    >
      <DatePicker.Label>Date and time</DatePicker.Label>
      <DatePicker.Control>
        <DatePicker.Trigger asChild unstyled>
          <Button variant="outline" width="full" justifyContent="space-between">
            {value[0]
              ? formatter.format(value[0].toDate(getLocalTimeZone()))
              : "Select date and time"}
            <LuCalendar />
          </Button>
        </DatePicker.Trigger>
      </DatePicker.Control>
      <Portal>
        <DatePicker.Positioner>
          <DatePicker.Content>
            <DatePicker.View view="day">
              <DatePicker.Header />
              <DatePicker.DayTable />
              <Input type="time" value={timeValue} onChange={onTimeChange} />
            </DatePicker.View>
          </DatePicker.Content>
        </DatePicker.Positioner>
      </Portal>
    </DatePicker.Root>
  )
}

